import{_ as n,o,c as e,a2 as i}from"./chunks/framework.Bix3-HpO.js";const c=JSON.parse('{"title":"Theme Navigation Menus","description":"Spinoko Theme Navigation Menus","frontmatter":{"title":"Theme Navigation Menus","description":"Spinoko Theme Navigation Menus","weight":160,"extra":{"order":160},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/spinoko/navigation"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/spinoko/navigation"}],["meta",{"property":"og:title","content":"Theme Navigation Menus"}],["meta",{"property":"og:description","content":"Spinoko Theme Navigation Menus"}],["meta",{"name":"twitter:title","content":"Theme Navigation Menus"}],["meta",{"name":"twitter:description","content":"Spinoko Theme Navigation Menus"}]]},"headers":[],"relativePath":"docs/spinoko/navigation.md","filePath":"docs/spinoko/navigation.md"}'),t={name:"docs/spinoko/navigation.md"};function s(r,a,d,l,h,p){return o(),e("div",null,[...a[0]||(a[0]=[i('<h1 id="spinoko-navigation-menus" tabindex="-1">Spinoko Navigation Menus <a class="header-anchor" href="#spinoko-navigation-menus" aria-label="Permalink to &quot;Spinoko Navigation Menus&quot;">​</a></h1><p>Spinoko has multiple navigation menus and you can even add one on your own. Learn more and how to do that below.</p><h2 id="navigation-menus" tabindex="-1">Navigation Menus <a class="header-anchor" href="#navigation-menus" aria-label="Permalink to &quot;Navigation Menus&quot;">​</a></h2><p>By default Spinoko has 2 navigation menus:</p><ol><li>Header navigation</li><li>Footer navigation</li></ol><p><code>💁 since version 2.4.0</code> you can <a href="#additional-navigation">add an additional nav menu</a> to the site header if you want.</p><h3 id="header-navigation" tabindex="-1">Header Navigation <a class="header-anchor" href="#header-navigation" aria-label="Permalink to &quot;Header Navigation&quot;">​</a></h3><p>Header navigation is the primary navigation menu of the theme and it&#39;s a hamburger menu, by default closed on all screens regardless of the screen size.</p><h3 id="footer-navigation" tabindex="-1">Footer Navigation <a class="header-anchor" href="#footer-navigation" aria-label="Permalink to &quot;Footer Navigation&quot;">​</a></h3><p>Footer navigation is an optional navigation menu and it&#39;s right above the copyright text in the theme footer area.</p><h3 id="additional-navigation" tabindex="-1">Additional Navigation <a class="header-anchor" href="#additional-navigation" aria-label="Permalink to &quot;Additional Navigation&quot;">​</a></h3><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-additional-navigation.png" alt="spinoko additional nav menu"></p><p><code>💁 since version 2.4.0</code> To display an additional (traditional) navigation menu on your website check the box for <strong>Customizer</strong> → <strong>Miscellaneous Options</strong> → <strong>Display Traditional Menu</strong> option.</p><p>After that visit <strong>Customizer</strong> → <strong>Menus</strong> and create a new menu (or use an existing one) to add it Additional menu location. Once you&#39;re happy with the results, publish the changes and it&#39;s done.</p><blockquote><p>Do not remove the main header (hamburger) navigation as it&#39;s displayed as the main menu on smaller screens.</p></blockquote>',15)])])}const m=n(t,[["render",s]]);export{c as __pageData,m as default};
